package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"

	_ "github.com/lib/pq"
)

type User struct {
	ID    int    `json:"id"`
	Email string `json:"email"`
}

type Order struct {
	ID         string  `json:"id"`
	UserID     int     `json:"user_id"`
	Product    string  `json:"product"`
	Quantity   int     `json:"quantity"`
	TotalPrice float64 `json:"total_price"`
	Status     string  `json:"status"`
	CreatedAt  string  `json:"created_at"`
}

type contextKey string

const userContextKey contextKey = "user"

func GetUserFromContext(ctx context.Context) (*User, bool) {
	user, ok := ctx.Value(userContextKey).(*User)
	return user, ok
}

type ErrorResponse struct {
	Error   string `json:"error"`
	Code    int    `json:"code"`
}

func writeJSON(w http.ResponseWriter, status int, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(data)
}

func writeError(w http.ResponseWriter, status int, message string) {
	writeJSON(w, status, ErrorResponse{
		Error: message,
		Code:  status,
	})
}

func extractOrderID(path string) (string, error) {
	// Expected path: /orders/{orderID}
	parts := strings.Split(strings.Trim(path, "/"), "/")
	if len(parts) < 2 {
		return "", fmt.Errorf("invalid path: order ID not found")
	}
	orderID := parts[len(parts)-1]
	if orderID == "" {
		return "", fmt.Errorf("order ID is empty")
	}
	return orderID, nil
}

func NewGetOrderHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			writeError(w, http.StatusMethodNotAllowed, "method not allowed")
			return
		}

		// Get authenticated user from context (set by auth middleware)
		user, ok := GetUserFromContext(r.Context())
		if !ok || user == nil {
			writeError(w, http.StatusUnauthorized, "unauthorized: user not found in context")
			return
		}

		// Extract order ID from URL path
		orderID, err := extractOrderID(r.URL.Path)
		if err != nil {
			writeError(w, http.StatusBadRequest, "invalid or missing order ID")
			return
		}

		// Query the database for the order
		var order Order
		query := `
			SELECT id, user_id, product, quantity, total_price, status, created_at
			FROM orders
			WHERE id = $1
		`
		err = db.QueryRowContext(r.Context(), query, orderID).Scan(
			&order.ID,
			&order.UserID,
			&order.Product,
			&order.Quantity,
			&order.TotalPrice,
			&order.Status,
			&order.CreatedAt,
		)

		if err == sql.ErrNoRows {
			writeError(w, http.StatusNotFound, "order not found")
			return
		}
		if err != nil {
			log.Printf("database error querying order %s: %v", orderID, err)
			writeError(w, http.StatusInternalServerError, "internal server error")
			return
		}

		// Ensure the order belongs to the authenticated user
		if order.UserID != user.ID {
			writeError(w, http.StatusForbidden, "forbidden: you do not have access to this order")
			return
		}

		writeJSON(w, http.StatusOK, order)
	}
}

// Example authentication middleware (for demonstration purposes)
func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// In a real application, this would validate a token/session
		// and retrieve the user from the database.
		// For demonstration, we simulate an authenticated user.
		user := &User{
			ID:    1,
			Email: "user@example.com",
		}
		ctx := context.WithValue(r.Context(), userContextKey, user)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func main() {
	db, err := sql.Open("postgres", "host=localhost port=5432 user=postgres password=postgres dbname=orders_db sslmode=disable")
	if err != nil {
		log.Fatalf("failed to connect to database: %v", err)
	}
	defer db.Close()

	if err := db.Ping(); err != nil {
		log.Fatalf("failed to ping database: %v", err)
	}

	mux := http.NewServeMux()

	orderHandler := NewGetOrderHandler(db)
	mux.Handle("/orders/", authMiddleware(http.HandlerFunc(orderHandler)))

	log.Println("server starting on :8080")
	if err := http.ListenAndServe(":8080", mux); err != nil {
		log.Fatalf("server failed: %v", err)
	}
}